const prettier = require("prettier");

module.exports = function (eleventyConfig) {
	// Set directories to pass through to the output folder
	eleventyConfig.addPassthroughCopy("./src/assets");
	eleventyConfig.addPassthroughCopy("_redirects");

	// Format all (HTML) files generated by Eleventy in the output folder
	eleventyConfig.addTransform("format-output-html", async function (content) {
		if (this.page.outputPath && this.page.outputPath.endsWith(".html")) {
			// Find the Prettier config file options
			const options = await prettier.resolveConfig();
			console.log(process.cwd());
			const formattedContent = await prettier.format(content, {
				filepath: this.page.outputPath,
				...options,
			});
			return formattedContent;
		}

		// you got the path of the configuration file
		// const configFilePath = await prettier.resolveConfigFile();
		// console.log(configFilePath);

		// const text = await fs.readFile(filePath, "utf8");
		// const options = await prettier.resolveConfig(filePath);
		// const formatted = await prettier.format(text, options);

		return content;
	});

	return {
		htmlTemplateEngine: "njk",
		dir: {
			input: "src",
			output: "_site",
			includes: "_includes",
			data: "_data",
		},
	};
};
